# lib/blog/sanitizer.ex
defmodule Blog.Sanitizer do
  @moduledoc """
  Sanitizes user-generated HTML content to prevent XSS attacks.
  Allows safe formatting tags while stripping dangerous elements.
  """

  # Define allowed tags and attributes for rich text
  @allowed_tags ~w(p br h1 h2 h3 h4 h5 h6 strong em b i u s strike
                    blockquote pre code ul ol li a img hr div span
                    table thead tbody tr th td figure figcaption)

  @allowed_attributes %{
    "a" => ["href", "title", "rel"],
    "img" => ["src", "alt", "title", "width", "height"],
    "td" => ["colspan", "rowspan"],
    "th" => ["colspan", "rowspan"],
    "div" => ["class"],
    "span" => ["class"],
    "pre" => ["class"],
    "code" => ["class"]
  }

  @doc """
  Sanitizes HTML content, allowing only safe tags and attributes.
  Strips all script tags, event handlers, and dangerous protocols.
  """
  def sanitize(nil), do: ""
  def sanitize(""), do: ""

  def sanitize(html) when is_binary(html) do
    html
    |> HtmlSanitizeEx.Scrubber.scrub(Blog.Sanitizer.Scrubber)
  end
end

