# lib/blog/posts.ex
defmodule Blog.Posts do
  alias Blog.Repo
  alias Blog.Posts.Post
  alias Blog.Sanitizer

  def create_post(attrs) do
    attrs = sanitize_content(attrs)

    %Post{}
    |> Post.changeset(attrs)
    |> Repo.insert()
  end

  def update_post(%Post{} = post, attrs) do
    attrs = sanitize_content(attrs)

    post
    |> Post.changeset(attrs)
    |> Repo.update()
  end

  defp sanitize_content(%{"content" => content} = attrs) when is_binary(content) do
    Map.put(attrs, "content", Sanitizer.sanitize(content))
  end

  defp sanitize_content(%{content: content} = attrs) when is_binary(content) do
    Map.put(attrs, :content, Sanitizer.sanitize(content))
  end

  defp sanitize_content(attrs), do: attrs
end

# lib/blog/posts/post.ex
defmodule Blog.Posts.Post do
  use Ecto.Schema
  import Ecto.Changeset

  schema "posts" do
    field :title, :string
    field :content, :string
    field :author_id, :integer

    timestamps()
  end

  def changeset(post, attrs) do
    post
    |> cast(attrs, [:title, :content, :author_id])
    |> validate_required([:title, :content])
    |> validate_length(:title, max: 255)
    |> validate_length(:content, max: 100_000)
  end
end

# lib/blog_web/helpers/sanitize_helpers.ex
defmodule BlogWeb.SanitizeHelpers do
  @moduledoc """
  Helper functions for safely rendering user-generated HTML content.
  NEVER use raw() directly on unsanitized user input.
  """

  use Phoenix.HTML

  @doc """
  Renders user-generated HTML content after sanitization.
  This is the ONLY safe way to render user HTML in templates.
  """
  def safe_html(nil), do: ""
  def safe_html(""), do: ""

  def safe_html(content) when is_binary(content) do
    content
    |> Blog.Sanitizer.sanitize()
    |> raw()
  end
end

# lib/blog_web/live/post_live/show.ex
defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  import BlogWeb.SanitizeHelpers

  alias Blog.Posts

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)

    {:ok,
     socket
     |> assign(:page_title, post.title)
     |> assign(:post, post)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <article class="blog-post">
      <header>
        <h1><%= @post.title %></h1>
        <time datetime={@post.inserted_at}>
          <%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %>
        </time>
      </header>

      <div class="post-content">
        <%!--
          SECURITY: We use safe_html/1 which sanitizes content before rendering.
          NEVER use raw(@post.content) directly — it enables XSS attacks.
        --%>
        <%= safe_html(@post.content) %>
      </div>
    </article>
    """
  end
end

# lib/blog_web/live/post_live/index.ex
defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  import BlogWeb.SanitizeHelpers

  alias Blog.Posts

  @impl true
  def mount(_params, _session, socket) do
    posts = Posts.list_posts()
    {:ok, assign(socket, :posts, posts)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="blog-posts">
      <h1>Blog Posts</h1>

      <div :for={post <- @posts} class="post-preview">
        <h2>
          <.link navigate={~p"/posts/#{post.id}"}>
            <%= post.title %>
          </.link>
        </h2>

        <div class="post-excerpt">
          <%= safe_html(truncate_html(post.content, 300)) %>
        </div>
      </div>
    </div>
    """
  end

  defp truncate_html(nil, _), do: ""

  defp truncate_html(content, max_length) when is_binary(content) do
    if String.length(content) > max_length do
      content
      |> String.slice(0, max_length)
      |> Kernel.<>("...")
    else
      content
    end
  end
end

# lib/blog_web/live/post_live/form.ex
defmodule BlogWeb.PostLive.Form do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Posts.Post

  @impl true
  def mount(_params, _session, socket) do
    changeset = Posts.change_post(%Post{})

    {:ok,
     socket
     |> assign(:page_title, "New Post")
     |> assign(:form, to_form(changeset))}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="post-form">
      <h1><%= @page_title %></h1>

      <.form for={@form} phx-change="validate" phx-submit="save">
        <div class="form-group">
          <.input field={@form[:title]} label="Title" type="text" required />
        </div>

        <div class="form-group">
          <label for="post-content">Content</label>
          <p class="help-text">
            You can use HTML formatting: &lt;strong&gt;, &lt;em&gt;, &lt;h2&gt;-&lt;h6&gt;,
            &lt;ul&gt;, &lt;ol&gt;, &lt;blockquote&gt;, &lt;a&gt;, &lt;img&gt;, &lt;code&gt;, etc.
          </p>
          <p class="security-note">
            Note: For security, script tags, event handlers, and unsafe attributes are automatically removed.
          </p>
          <textarea
            id="post-content"
            name={@form[:content].name}
            rows="20"
            required
          ><%= @form[:content].value %></textarea>
          <.error :for={msg <- Enum.map(@form[:content].errors, &translate_error/1)}>
            <%= msg %>
          </.error>
        </div>

        <button type="submit" class="btn btn-primary">Publish Post</button>
      </.form>
    </div>
    """
  end

  @impl true
  def handle_event("validate", %{"post" => post_params}, socket) do
    changeset =
      %Post{}
      |> Posts.change_post(post_params)
      |> Map.put(:action, :validate)

    {:noreply, assign(socket, :form, to_form(changeset))}
  end

  @impl true
  def handle_event("save", %{"post" => post_params}, socket) do
    # Content is sanitized in Posts.create_post/1
    case Posts.create_post(post_params) do
      {:ok, post} ->
        {:noreply,
         socket
         |> put_flash(:info, "Post published successfully!")
         |> push_navigate(to: ~p"/posts/#{post.id}")}

      {:error, changeset} ->
        {:noreply, assign(socket, :form, to_form(changeset))}
    end
  end

  defp translate_error({msg, opts}) do
    Enum.reduce(opts, msg, fn {key, value}, acc ->
      String.replace(acc, "%{#{key}}", fn _ -> to_string(value) end)
    end)
  end
end

# Optional: Content Security Policy plug for defense in depth
# lib/blog_web/plugs/content_security_policy.ex
defmodule BlogWeb.Plugs.ContentSecurityPolicy do
  @moduledoc """
  Sets Content-Security-Policy headers as defense-in-depth against XSS.
  """
  import Plug.Conn

  def init(opts), do: opts

  def call(conn, _opts) do
    put_resp_header(
      conn,
      "content-security-policy",
      "default-src 'self'; " <>
        "script-src 'self'; " <>
        "style-src 'self' 'unsafe-inline'; " <>
        "img-src 'self' https:; " <>
        "object-src 'none'; " <>
        "base-uri 'self'; " <>
        "frame-ancestors 'none'"
    )
  end
end